class Solution:
    def numberWays(self, hats):
        MOD = 10**9 + 7
        n = len(hats)
        # brute force: try all assignments with backtracking (only feasible for small n)
        # build hat->people map
        from collections import defaultdict
        hat_to_people = defaultdict(list)
        for i, prefs in enumerate(hats):
            for h in prefs:
                hat_to_people[h].append(i)
        full = (1 << n) - 1
        dp = [0] * (1 << n)
        dp[0] = 1
        for hat in range(1, 41):
            new_dp = dp[:]
            for mask in range(full + 1):
                if dp[mask] == 0:
                    continue
                for p in hat_to_people[hat]:
                    if mask & (1 << p) == 0:
                        new_dp[mask | (1 << p)] = (new_dp[mask | (1 << p)] + dp[mask]) % MOD
            dp = new_dp
        return dp[full]

