var numberWays = function(hats) {
    const MOD = 1000000007n;
    const n = hats.length;
    const hatToPeople = Array.from({length: 41}, () => []);
    for (let i = 0; i < n; i++) for (const h of hats[i]) hatToPeople[h].push(i);
    const full = (1 << n) - 1;
    const dp = new Array(full + 1).fill(0n);
    dp[0] = 1n;
    for (let hat = 1; hat <= 40; hat++) {
        const newDp = dp.slice();
        for (let mask = 0; mask <= full; mask++) {
            if (dp[mask] === 0n) continue;
            for (const p of hatToPeople[hat]) {
                if (!(mask & (1 << p))) {
                    newDp[mask | (1 << p)] = (newDp[mask | (1 << p)] + dp[mask]) % MOD;
                }
            }
        }
        for (let i = 0; i <= full; i++) dp[i] = newDp[i];
    }
    return Number(dp[full]);
};
